external_knowledge:
- 'inactive sites' refers to sites with status 'inactive' in the database;
- 'past week' refers to the last seven days from the current date;
- 'lowest costs' means the minimum generator usage cost recorded for each site;
- 'not free' implies costs greater than zero USD.

sql:
SELECT MAX(battery_charge_level_kWh) AS max_battery_charge_level
FROM energy_data
WHERE energy_loss_kWh < 5 AND battery_id = 1;

SELECT * 
FROM energy_data
ORDER BY timestamp;

SELECT SUM(lost_load_usd) AS total_lost_load_usd
FROM energy_data
WHERE site_id = 1;

SELECT record_id, timestamp, site_id, battery_id
FROM energy_data
WHERE energy_loss_kWh > (SELECT AVG(energy_loss_kWh) FROM energy_data);

SELECT DISTINCT battery_name 
FROM batteries 
WHERE status <> 'decommissioned' AND capacity_kWh < 30.5;
